import base64, os

DATA = """

"""

out_path = os.path.join('core', 'claim_registry.py')
os.makedirs('core', exist_ok=True)
with open(out_path, 'wb') as f:
    f.write(base64.b64decode(DATA.strip()))

lines = open(out_path, encoding='utf-8').readlines()
print(f'OK: записано {len(lines)} строк -> {out_path}')
